import{o as p,c as e,D as t}from"./framework.54301fec.js";const a='{"title":"Глава 13","description":"","frontmatter":{"title":"Глава 13","subtitle":"Малини виджайоттара тантра","tags":"malini","date":"2020-08-10T00:00:00.000Z"},"headers":[{"level":2,"title":"Тринадцатая глава","slug":"тринадцатая-гnава"}],"relativePath":"texts/malini-vijayottara/13.md","lastUpdated":1624912959902}',r={},l=t('<h2 id="тринадцатая-гnава"><a class="header-anchor" href="#тринадцатая-гnава" aria-hidden="true">#</a> Тринадцатая глава</h2><p>Теперь поведаю Варуни дхарану. Посредством успеха в ней, (йогин) становится владыкой вод ..1.</p><p>Следует созерцать (свое) тело, пребывающее среди воды, белое, прохладное, круглое. Ничто иное внутри и снаружи йогин не должен созерцать ..2.</p><p>Благодаря этой практике он за семь дней он обретет мягкость. За месяц он непременно станет преодолевшим болезнь желчи (желтуху) ..3.</p><p>За год владыка йоги обретет нежное тело, нежный взгляд, развевающуюся на ветру шевелюру, за три года (станет) подобным облаку ..4.</p><p>Это именуется первой, чистой Варуни дхараной. Теперь вновь поведаю о ее подразделениях ..5.</p><p>Следует созерцать, как и раньше, свое тело слева и справа, белое, пребывающее над водой, о Деви, пребывающей внутри (йогина) ..6.</p><p>За семь дней (йогин) освободится от всех болезней, происходящих от желчи. За шесть месяцев появится устойчивость, если они пребывает в единстве с нею (водой) ..7.</p><p>За три года появится знание окружения воды, он не будет затронут разделениями, повсюду (пребывая) подобно Варуне (воде). Он достигнет варуна таттву, если будет практиковать постепенно (эти) уровни. Следует, как прежде, (созерцать) себя, пребывающего в середине горла (размером) 12 ангул ..8-9.</p><p>Созерцающий владыку таттвы воды, непременно быстро узрит (его). Это видение будет устойчивым. В пятом (уровне наступит) пребывание в своей изначальной форме ..10.</p><p>Во втором подразделении, став устойчивым, наделенным (светом) лунного диска, он затем достигнет единства с ним, затем (единства) с формой сакалы ..11.</p><p>Следует созерцать как тело наполняется сиянием, белого цвета. Затем оно становится устойчивым. Затем наступает пребывание в чрезвычайной устойчивости ..12.</p><p>Затем следует созерцать свет груды жемчуга и лунного диска. Преодолев неустойчивость, вторым он обретет устойчивость ..13.</p><p>Затем следует созерцать белый свет этого сияния. (Благодаря этому, йогин) обретет положение видйешвары, происходящее из окружения воды ..14.</p><p>Созерцая свое тело наполненным им, пребывающим в белом свете, (йогин) обретет всевластие, чрезвычайно устойчиво пребывая в чрезвычайной устойчивости ..15.</p><p>Единство с созерцаемой таттвой (обретается) на третьем уровне. На втором происходит осознание ее владыки ..16.</p><p>Или же на втором (уровне) знающий йогу станет устойчиво единым с ней. На шестом он обретет всевладычество, но если (задержится) на втором, то (обретет) гибель. Таковы все подразделения таттвы (составляющие) 15 сущностей, разнообразно постигаемых, знающими правила, наделяющими совершенствами пяти плодов ..17-18.</p><p>Благодаря этому происходит внутренний плод о котором говорилось и (снова) говорится. Познаваемое, которое является плодом единства с ней, есть все, без сомнения ..19.</p><p>Эта именуется варуни (дхараной), подразделяемой на пятнадцать. Ради совершенства йогинов в йоге услышь об агнеи (дхаране) ..20.</p><p>Следует созерцать в теле треугельник, содержащий красное пламя. (благодаря этому) за семь дней, о Деви, (у йогина) появится острота ..21.</p><p>За месяц садхака избавится от всех (болезней), происходящих от ветра и слизи. Он станет лишенным сна, многоедящим, производящим много кала и мочи ..22.</p><p>По прошествии трех месяцев, он по желанию сможет переварить любую вещь. За три года, став единым с огнем, он сможет играть с огнем ..23.</p><p>Разгневанный, он сможет все сжечь вместе с лесами горами по желанию. Следует созерцать себя, пребывающего в треугольной мандале ..24.</p><p>Старательно, слева и справа и повсюду. За семь дней, (йогин) станет лишенным болезней, за шесть месяцев единым с огнем ..25.</p><p>За три года он полностью сможет видеть таттву огня. В зависимости от того, какова способность (шакти), каково видение, в таком пребывании он будет устойчив ..26.</p><p>Созерцая себя как прежде пребывающим в небе, цвета пламени, увидит по порядку владык таттвы огня ..27.</p><p>Созерцающий в центре огонь, являющийся в окружении дыма, обликом подобный солнечному диску, станет единым с владыкой таттвы огня ..28.</p><p>Следует созерцать <em>сакалу</em>, светом устраняющего сеть тьмы, сияющего подобно огню без дыма, (тогда йогин) достигнет владычества над ним ..29.</p><p>Следует созерцать образ дневного света и огня а в нем – огонь. Тогда он обретет подобие ему. В нем он пребудет недвижимо ..30.</p><p>Там он должен сиять блеском, подобно блеску драгоценностей. Пребывая в единстве с ним йогин обретет положение мантреши ..31.</p><p>Следует созерцать внутри и снаружи, огонь, пребывающий повсюду. Благодаря этому (йогин) не покинет это положение, неуничтожимое и неделимое ..32.</p><p>При гибели (мира он достигнет) высшего положения покоя, (которое есть) Шанкара. Так (Тебе) названа пятнадцатичеричная вахни дхарана ..33.</p><p>Следует созерцать свое тело, черное подвижное, наделенное 6 направлениями (<em>вправо, влево, вперед, назад, вверх, вниз</em>) и 5 действиями (<em>подбрасывание, падение, сжатие, расширение, движение</em>), прохладное, движущееся со звуком чу-чу (в этом заключена) ваяви дхарана ..34.</p><p>По устранении болезней, происходящих от капхи, происходит подвижность, подобная ветру. За шесть месяцев практики йогин, (достигнет) пребывания в этом положении.35.</p><p>За час (мухурту) сможет преодолеть сто йоджан. За три года он станет непосредственной формой ветра ..36.</p><p>Он сможет выветривать горы и выкорчевывать деревья. Разгневанный, он будет повелевать Шакрой (Индрой), и тот, лишенный сил, будет прислуживать ему ..37.</p><p>Следует созерцать собственное тело голубого цвета. За шесть месяцев (йогин) достигнет всего, как было сказано раньше, без сомнения ..38.</p><p>За три года он узрит ваю таттву, пребывая в единстве с ней. В межбровии следует созерцать форму Атмана (себя) цвета туши ..39.</p><p>(Тогда йогин) узрит всех чистых владык ваю таттвы, действующих в совокупности чувств, цвета неба, обликом подобных солнечному диску ..40.</p><p>Созерцающий ее, достигает единства с ней. Когда это произойдет, он погрузится в нее. Там следует созерцать сакалу, являющуюся как небо, разбитое Индрой (молнией) ..41.</p><p>Он достигнет природы мантреши, затем владычества над ней. При созерцании его всепроникающей варны, он достигнет ее могущества ..42.</p><p>Затем он достигает Превосходства над ней, скользящей вверх и вниз. Такова поведанная божественная ваю дхарана ..43.</p><p>Созерцая свое тело, подобное ветру и его отсутствие, йогин за семь дней достигнет пустотности ..44.</p><p>За месяц, даже атакованный владыками наслаждений, он не смутится, оставив болезни, свободный от лихорадки ..45.</p><p>За шесть месяцев он сможет проходит сквозь узкие отверстия, подобно пространству. За три с половиной года он станет подобным пространству ..46.</p><p>По желанию (он сможет принимать) огромное тело, по желанию – малое, крепкое, (неделимое) нерушимое. Он узрит Медини;.47.</p><p>(Ароматом) подобную нектару сотен предложенных цветов, (цветом) подобную миллиарду утроб зари. Созерцая (так) тело, за три года у него появится знание пространства ..48.</p><p>Описанный выше плод он обретет за семь дней. Во лбу следует созерцать Себя размером 12 ангул, .49.</p><p>Он узрит по порядку всех владык этой таттвы, стоящих впереди (него). Созерцая (себя) цвета лунного диска, закрытого Раху, он станет единым с ней ..50.</p><p>Следует созерцать сакалу, в виде лунного диска, пребывающую там. Благодаря этому лунному свету он обретет природу мантреши ..51.</p><p>Благодаря этому, скользя вниз, внутри и снаружи, мудрый, достигнув природы мантреши, достигает несравненного знания ..52.</p><p>Благодаря ему, скользящему вверх, через свет в форме амриты и достигнувшему свободы, ему никто не сможет противостоять ..53.</p><p>Итак названная дхарана пяти таттв пребывающая в чистых адхавах, пятирично охватывает сознание существа ..54.</p><p>В них помещается сознание, являющееся сущностью растворения виши и прочего отличного от сознания, которое происходит по собственной Воле ..55.</p><p>Следует сделать осознание устойчивым, этим обретается его плод. Оно должно стать единым, не подверженным внутреннему разделению ..56.</p><p>Кто достигает пребывание внутри, не должен останавливаться, совершающий остановку, не достигнет высшего плода ..57.</p><p>При обретении совершенств пяти дхаран йогины обретают 11 совершенств пишачей, и пять совершенств Индры. Так подразделяются йогины ..58.</p><p>Практикуя по порядку в пятнадцати уровнях желанные (сиддхи) обретаются за три года от начала (практики), а некоторые за два и один (год) ..59.</p><p>Иные за шесть месяцев и пять месяцев, четыре и три, два и один, за (одну) пакшу, за пятнадцать и десять дней;.60.</p><p>Три, два или один, согласно множеству желаний как было описано выше. (Йогин), насладившись желанными сиддхи, обретет вечное положение ..61. [small]Такова в священной «Малини виджайоттара тантре» тринадцатая глава [/small]</p>',60);r.render=function(t,a,r,i,s,m){return p(),e("div",null,[l])};export default r;export{a as __pageData};
